import re

# Read the file
with open(r"Interface\send_projects_emails.py", "r") as f:
    content = f.read()

# New base64 logo - correct Spark PNG
new_logo = ''

# Replace all instances of the old base64 string in spark_logo_base64 assignments
# Find lines that look like: spark_logo_base64 = "iVBORw0K..."
old_patterns = [
    # Old truncated pattern from file
    r'spark_logo_base64 = "iVBORw0KGgoAAAANSUhEUgAAAHgAAAB4CAYAAAA5ZDbS[^"]*"',
]

for pattern in old_patterns:
    content = re.sub(pattern, f'spark_logo_base64 = "{new_logo}"', content)

# Write the file back
with open(r"Interface\send_projects_emails.py", "w") as f:
    f.write(content)

print("✓ Logo base64 strings updated successfully!")
